import React, { useEffect, useState } from "react";
import Dashboard from "./Dashboard";
import AddTask from "./AddTask";

export default function TaskList() {
  const [tasks, setTasks] = useState([]);
  const [title, setTitle] = useState("");
  const [dueDate, setDueDate] = useState("");
  const [notifications, setNotifications] = useState([]);

  const fetchAll = async () => {
    try {
      const t = await fetch("http://localhost:8086/tasks").then(r => r.json());
      const n = await fetch("http://localhost:8086/tasks/notifications").then(r => r.json());

      setTasks(t);
      setNotifications(n);
    } catch (err) {
      console.error("Error fetching data:", err);
    }
  };

  useEffect(() => { fetchAll(); }, []);

  const addTask = async () => {
    if (!title || !dueDate) {
      alert("Please fill all fields");
      return;
    }

    try {
      await fetch("http://localhost:8086/tasks", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ title, dueDate })
      });

      setTitle("");
      setDueDate("");
      fetchAll();
    } catch (err) {
      console.error("Error adding task:", err);
    }
  };

  const suggest = async () => {
    try {
      await fetch("http://localhost:8086/tasks/suggest", { method: "POST" });
      fetchAll();
    } catch (err) {
      console.error("Error suggesting task:", err);
    }
  };

  const completeTask = async (id) => {
    await fetch(`http://localhost:8086/tasks/${id}/complete`, {
      method: "PUT"
    });
    fetchAll();
  };

  return (
    <div className="bg-gray-100 min-h-screen p-6">
      <Dashboard />

      {/* Notifications */}
      {notifications.length > 0 && (
        <div className="bg-red-500 text-white p-3 rounded mb-4">
          ⚠ {notifications.length} tasks due soon!
        </div>
      )}

      {/* ✅ Add Task Component */}
      <AddTask onTaskAdded={fetchAll} />

      {/* AI Suggest */}
      <button
        onClick={suggest}
        className="bg-purple-600 text-white px-4 py-2 rounded-xl mb-6 mt-4 hover:bg-purple-700 transition"
      >
        🤖 AI Suggest Task
      </button>

      {/* Tasks */}
      <div className="space-y-3">
        {tasks.map(t => (
          <div
            key={t.id}
            className="bg-white p-4 rounded-xl shadow flex justify-between items-center"
          >
            <div>
              <div className="font-semibold text-gray-800">{t.title}</div>
              <div className="text-sm text-gray-500">
                {t.priority} | {t.dueDate}
              </div>
            </div>

            {!t.completed && (
              <button
                onClick={() => completeTask(t.id)}
                className="bg-green-500 text-white px-4 py-2 rounded-lg hover:bg-green-600"
              >
                Done
              </button>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}
